parameters.jsCode:
const t = $('Execute Workflow Trigger').item.json;

const vmObject = {
  type: 'VirtualMachine',
  name: t.vmName,
  objectId: t.objectId,
  platform: 'VSphere',
  hostName: t.hostName
};

const body = {
  type: 'VSphereBackup',
  name: t.jobName,
  description: t.jobDescription || 'Created by BackupPaw',
  isHighPriority: false,
  virtualMachines: {
    includes: [vmObject],
    excludes: {
      vms: [],
      disks: [],
      templates: { isEnabled: false, excludeFromIncremental: false }
    }
  },
  storage: {
    backupRepositoryId: t.repositoryId,
    backupProxies: { autoSelectEnabled: true, proxyIds: [] },
    retentionPolicy: { type: 'RestorePoints', quantity: parseInt(t.retentionPoints) || 7 },
    gfsPolicy: {
      isEnabled: false,
      weekly:  { desiredTime: 'sunday',  isEnabled: false, keepForNumberOfWeeks: 1 },
      monthly: { desiredTime: 'First',   isEnabled: false, keepForNumberOfMonths: 1 },
      yearly:  { desiredTime: 'January', isEnabled: false, keepForNumberOfYears: 1 }
    },
    advancedSettings: {
      backupModeType: 'Incremental',
      synthenticFulls: { isEnabled: true },
      activeFulls: {
        isEnabled: true,
        weekly: { isEnabled: true, days: ['saturday'] },
        monthly: { dayOfWeek: 'monday', dayNumberInMonth: 'First', isEnabled: false, dayOfMonth: 1,
          months: ['January','February','March','April','May','June','July','August','September','October','November','December'] }
      },
      backupHealth: {
        isEnabled: true,
        weekly: { isEnabled: false, days: ['friday'] },
        monthly: { dayOfWeek: 'monday', dayNumberInMonth: 'First', isEnabled: true, dayOfMonth: 1,
          months: ['January','February','March','April','May','June','July','August','September','October','November','December'] }
      },
      fullBackupMaintenance: {
        RemoveData: { isEnabled: false, afterDays: 14 },
        defragmentAndCompact: {
          isEnabled: false,
          weekly:  { isEnabled: false, days: ['saturday'] },
          monthly: { dayOfWeek: 'saturday', dayNumberInMonth: 'Last', isEnabled: false, dayOfMonth: 1,
            months: ['January','February','March','April','May','June','July','August','September','October','November','December'] }
        }
      },
      storageData: {
        compressionLevel: 'Optimal',
        storageOptimization: 'LocalTarget',
        inlineDataDedupEnabled: true,
        excludeSwapFileBlocks: true,
        excludeDeletedFileBlocks: true,
        encryption: { isEnabled: false }
      },
      notifications: {
        sendSNMPNotifications: false,
        emailNotifications: { isEnabled: false, notificationType: null, recipients: [], customNotificationSettings: null },
        vmAttribute: { isEnabled: false, notes: '', appendToExistingValue: false }
      },
      vSphere: {
        enableVMWareToolsQuiescence: false,
        changedBlockTracking: { isEnabled: true, enableCBTautomatically: true, resetCBTonActiveFull: true }
      },
      storageIntegration: { isEnabled: true, processedVmsLimitEnabled: true, processedVmsCount: 13, failoverToStandardBackup: true },
      scripts: {
        preCommand:  { isEnabled: false, command: '' },
        postCommand: { isEnabled: false, command: '' }
      }
    }
  },
  guestProcessing: {
    appAwareProcessing: { isEnabled: false, appSettings: [] },
    guestFSIndexing: { isEnabled: false, indexingSettings: [] },
    guestInteractionProxies: { autoSelectEnabled: true, proxyIds: [] },
    guestCredentials: { credentialsPerMachine: [], useAgentManagementCredentials: false }
  },
  schedule: {
    daily: {
      dailyKind: 'Everyday',
      isEnabled: true,
      localTime: t.scheduleTime || '22:00',
      days: ['sunday','monday','tuesday','wednesday','thursday','friday','saturday']
    },
    monthly: {
      dayOfWeek: 'saturday', dayNumberInMonth: 'Fourth', isEnabled: false,
      localTime: '22:00', dayOfMonth: 1,
      months: ['January','February','March','April','May','June','July','August','September','October','November','December']
    },
    periodically: { periodicallyKind: 'Hours', isEnabled: false, frequency: 0 },
    retry: { isEnabled: true, retryCount: 3, awaitMinutes: 10 },
    backupWindow: { isEnabled: false },
    runAutomatically: true
  }
};

return [{ json: { body: JSON.stringify(body) } }];
